import { serve } from "@hono/node-server";
import { serveStatic } from "@hono/node-server/serve-static";
import { Hono } from "hono";
import { cors } from "hono/cors";
import { createHub } from "honohub";
import hubConfig from "../hub.config";

const app = new Hono().use(cors()).route("/", createHub(hubConfig));

const pathValidationRegex = /^\/[a-zA-Z0-9\/-]*(?<!\.[a-zA-Z0-9]+)$/;
app.use(
  "/*",
  serveStatic({
    root: "./apps/sandbox/dist",
    rewriteRequestPath: (path) => {
      const isPath = pathValidationRegex.test(path);

      if (isPath) return "/";
      return path;
    },
  }),
);

const port = 3000;
console.log(`Server is running on port ${port}`);

serve({
  fetch: app.fetch,
  port,
});

trimTrailingSlash = (options?: TrimTrailingSlashOptions): MiddlewareHandler => {
  return async function trimTrailingSlash(c, next) {
    if (options?.alwaysRedirect) {
      if (
        (c.req.method === 'GET' || c.req.method === 'HEAD') &&
        c.req.path !== '/' &&
        c.req.path.at(-1) === '/'
      ) {
        const url = new URL(c.req.url)
        url.pathname = url.pathname.substring(0, url.pathname.length - 1)

        return c.redirect(url.toString(), 301)
      }
    }

    await next()

    if (
      !options?.alwaysRedirect &&
      c.res.status === 404 &&
      (c.req.method === 'GET' || c.req.method === 'HEAD') &&
      c.req.path !== '/' &&
      c.req.path.at(-1) === '/'
    ) {
      const url = new URL(c.req.url)
      url.pathname = url.pathname.substring(0, url.pathname.length - 1)

      c.res = c.redirect(url.toString(), 301)
    }
  }
}

appendTrailingSlash = (options?: AppendTrailingSlashOptions): MiddlewareHandler => {
  return async function appendTrailingSlash(c, next) {
    if (options?.alwaysRedirect) {
      if (
        (c.req.method === 'GET' || c.req.method === 'HEAD') &&
        c.req.path.at(-1) !== '/' &&
        !options.skip?.(c.req.path)
      ) {
        const url = new URL(c.req.url)
        url.pathname += '/'

        return c.redirect(url.toString(), 301)
      }
    }

    await next()

    if (
      !options?.alwaysRedirect &&
      c.res.status === 404 &&
      (c.req.method === 'GET' || c.req.method === 'HEAD') &&
      c.req.path.at(-1) !== '/' &&
      !options?.skip?.(c.req.path)
    ) {
      const url = new URL(c.req.url)
      url.pathname += '/'

      c.res = c.redirect(url.toString(), 301)
    }
  }
}

isValidStylePropertyName = (name: string): boolean => {
  if (validStylePropertyNameCache.has(name)) {
    return true
  }
  const len = name.length
  if (len === 0) {
    return false
  }
  for (let i = 0; i < len; i++) {
    const c = name.charCodeAt(i)
    if (
      !(
        (c >= 0x61 && c <= 0x7a) || // a-z
        (c >= 0x41 && c <= 0x5a) || // A-Z
        (c >= 0x30 && c <= 0x39) || // 0-9
        c === 0x2d || // -
        c === 0x5f // _
      )
    ) {
      // non-fast-path character found — fall back to regex for the full name
      if (!invalidStylePropertyNameCharRe.test(name)) {
        cacheValidName(validStylePropertyNameCache, validStylePropertyNameCacheMax, name)
        return true
      } else {
        return false
      }
    }
  }
  cacheValidName(validStylePropertyNameCache, validStylePropertyNameCacheMax, name)
  return true
}

const normalizeIncomingMethod = (method: unknown): string => {
  if (typeof method !== 'string' || method.length === 0) {
    return 'GET'
  }

  // fast path for already-uppercase common methods from Node.js.
  switch (method) {
    case 'DELETE':
    case 'GET':
    case 'HEAD':
    case 'OPTIONS':
    case 'POST':
    case 'PUT':
      return method
  }

  const upper = method.toUpperCase()
  switch (upper) {
    case 'DELETE':
    case 'GET':
    case 'HEAD':
    case 'OPTIONS':
    case 'POST':
    case 'PUT':
      return upper
    default:
      return method
  }
}

async function findClosestMatchingSections(
  bucket: R2Bucket,
  question: string,
  options?: {
    r2Key?: string
    limit?: number
  },
): Promise<AskSearchResult[]> {
  const key = options?.r2Key ?? ASK_INDEX_R2_KEY
  const limit = Math.max(1, Math.min(16, Math.floor(options?.limit ?? 6)))
  const q = normalizeAskSearchQuestion(question)
  if (q === '') return []

  const { fuse, rowCount } = await getIndex(bucket, key)
  if (rowCount === 0) return []

  const hits = fuse.search(q, { limit: limit * 3 })
  const seen = new Set<string>()
  const results: AskSearchResult[] = []
  for (const hit of hits) {
    const result = rowToResult(hit.item)
    const key = `${result.filename}/${result.nest_filename ?? ''}#${result.section_id}`
    if (seen.has(key)) continue
    seen.add(key)
    results.push(result)
    if (results.length >= limit) break
  }
  return results
}

const SwaggerUI = ({ baseUrl, version, ...options }: SwaggerUIOptions): string => {
  const asset = remoteAssets({
    baseUrl: baseUrl,
    version: version,
  })

  if (options.manuallySwaggerUIHtml) {
    return options.manuallySwaggerUIHtml(asset)
  }

  const optionsStrings = renderSwaggerUIOptions(options)

  return `
    <div>
      <div id="swagger-ui"></div>
      ${asset.css.map((url) => html`<link rel="stylesheet" href="${url}" />`)}
      ${asset.js.map((url) => html`<script src="${url}" crossorigin="anonymous"></script>`)}
      <script>
        window.onload = () => {
          window.ui = SwaggerUIBundle({
            dom_id: '#swagger-ui',${optionsStrings},
          })
        }
      </script>
    </div>
  `
}

securityHeadersMiddleware = () => {
  return async (c: Context, next: Next) => {
    await next()

    c.header('X-Content-Type-Options', 'nosniff')
    c.header('X-Frame-Options', 'SAMEORIGIN')
    c.header('Referrer-Policy', 'strict-origin-when-cross-origin')
    c.header('Permissions-Policy', 'camera=(), microphone=(), geolocation=()')

    // Only set HSTS in non-development environments
    const environment = (c.env as any)?.ENVIRONMENT
    if (environment !== 'development') {
      c.header('Strict-Transport-Security', 'max-age=31536000; includeSubDomains')
    }
  }
}

export async function parseBody(req: Request): Promise<Record<string, unknown>> {
  const contentType = req.headers.get('content-type')

  switch (contentType) {
    case 'application/graphql':
      return { query: await req.text() }
    case 'application/json':
      try {
        return await req.json()
      } catch (e) {
        if (e instanceof Error) {
          console.error(`${e.stack || e.message}`)
        }
        throw Error(`POST body sent invalid JSON: ${e}`)
      }
    case 'application/x-www-form-urlencoded':
      return parseFormURL(req)
  }

  return {}
}

removeNode = (node: Node): void => {
  if (!isNodeString(node)) {
    node[DOM_STASH]?.[1][STASH_EFFECT]?.forEach((data: EffectData) => data[2]?.())

    refCleanupMap.get(node.e as Element)?.()
    if (node.p === 2) {
      node.vC?.forEach((n) => (n.p = 2))
    }
    node.vC?.forEach(removeNode)
  }
  if (!node.p) {
    node.e?.remove()
    delete node.e
  }
  if (typeof node.tag === 'function') {
    updateMap.delete(node)
    fallbackUpdateFnArrayMap.delete(node)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    delete (node as any)[DOM_STASH][3] // delete explicitly for avoid circular reference
    node.a = true
  }
}

function compareKey(a: string, b: string): number {
  if (a.length === 1) {
    return b.length === 1 ? (a < b ? -1 : 1) : -1
  }
  if (b.length === 1) {
    return 1
  }

  // wildcard
  if (a === ONLY_WILDCARD_REG_EXP_STR || a === TAIL_WILDCARD_REG_EXP_STR) {
    return 1
  } else if (b === ONLY_WILDCARD_REG_EXP_STR || b === TAIL_WILDCARD_REG_EXP_STR) {
    return -1
  }

  // label
  if (a === LABEL_REG_EXP_STR) {
    return 1
  } else if (b === LABEL_REG_EXP_STR) {
    return -1
  }

  return a.length === b.length ? (a < b ? -1 : 1) : b.length - a.length
}

buildRegExpStr(): string {
  const childKeys = Object.keys(this.#children).sort(compareKey)

  const strList = childKeys.map((k) => {
    const c = this.#children[k]
    return (
      (typeof c.#varIndex === 'number'
        ? `(${k})@${c.#varIndex}`
        : regExpMetaChars.has(k)
          ? `\\${k}`
          : k) + c.buildRegExpStr()
    )
  })

  if (typeof this.#index === 'number') {
    strList.unshift(`#${this.#index}`)
  }

  if (strList.length === 0) {
    return ''
  }
  if (strList.length === 1) {
    return strList[0]
  }

  return '(?:' + strList.join('|') + ')'
}

#buildMatcher(method: string): Matcher<T> | null {
  const routes: [string, HandlerWithMetadata<T>[]][] = []

  let hasOwnRoute = method === METHOD_NAME_ALL

  ;[this.#middleware!, this.#routes!].forEach((r) => {
    const ownRoute = r[method]
      ? Object.keys(r[method]).map((path) => [path, r[method][path]])
      : []
    if (ownRoute.length !== 0) {
      hasOwnRoute ||= true
      routes.push(...(ownRoute as [string, HandlerWithMetadata<T>[]][]))
    } else if (method !== METHOD_NAME_ALL) {
      routes.push(
        ...(Object.keys(r[METHOD_NAME_ALL]).map((path) => [path, r[METHOD_NAME_ALL][path]]) as [
          string,
          HandlerWithMetadata<T>[],
        ][])
      )
    }
  })

  if (!hasOwnRoute) {
    return null
  } else {
    return buildMatcherFromPreprocessedRoutes(routes)
  }
}

function mcpWellKnownRoutes(baseUrl: string) {
  const wellKnown = new Hono();

  wellKnown.get("/.well-known/oauth-protected-resource/api/mcp", (c) =>
    c.json({
      resource: `${baseUrl}/api/mcp`,
      authorization_servers: [`${baseUrl}/api`],
    }),
  );

  wellKnown.get("/.well-known/oauth-authorization-server/api", (c) =>
    c.json({
      issuer: `${baseUrl}/api`,
      authorization_endpoint: `${baseUrl}/api/mcp/authorize`,
      token_endpoint: `${baseUrl}/api/mcp/token`,
      registration_endpoint: `${baseUrl}/api/mcp/register`,
      response_types_supported: ["code"],
      grant_types_supported: ["authorization_code"],
      code_challenge_methods_supported: ["S256"],
      token_endpoint_auth_methods_supported: ["none"],
    }),
  );

  return wellKnown;
}

constructor(
  status: ErrorSchemaType['status'],
  type: ErrorKey,
  severity: ErrorSchemaType['severity'],
  opts?: AppErrorOpts,
) {
  const i18nOpts = { ns: ['appError', 'error'], defaultValue: opts?.name ?? 'Unknown error' };
  const messageFallback = opts?.message ?? i18n.t(type, i18nOpts);
  super(i18n.t(`${type}.text`, { ...i18nOpts, defaultValue: messageFallback }));

  this.name = opts?.name ?? i18n.t(type, { ...i18nOpts, defaultValue: 'ApiError' });
  this.status = status;
  this.type = type;
  this.entityType = opts?.entityType;
  this.severity = severity;
  this.willRedirect = opts?.willRedirect ?? false;
  this.meta = opts?.meta;
  this.stack = opts?.originalError?.stack ?? this.stack;
  this.cause = opts?.originalError?.cause;
}

sendLockoutEmail = (rateLimitKey: string, type: 'totp-lockout') => {
  const email = emailFromKey(rateLimitKey);
  if (!email) return;

  const duration = Math.round(defaultOptions.blockDuration / 60);

  db.select({ email: usersTable.email, name: usersTable.name, language: usersTable.language })
    .from(usersTable)
    .where(eq(usersTable.email, email))
    .limit(1)
    .then(([user]) => {
      if (user)
        sendAccountSecurityEmail(null, user, type, {
          attempts: String(defaultOptions.points),
          duration: String(duration),
        });
    })
    .catch(() => {});
}

function getUploadTokenOp(ctx: AuthContext, { isPublic, organizationId, templateId }: GetUploadTokenOpts) {
  const user = ctx.var.user;

  const sub = [organizationId, user.id].filter((part): part is string => typeof part === 'string').join('/');

  if (!env.TRANSLOADIT_KEY || !env.TRANSLOADIT_SECRET) {
    return { sub, public: isPublic, s3: !!env.S3_ACCESS_KEY_ID, params: null, signature: null };
  }

  try {
    const params = getParams(templateId, isPublic, sub);
    const paramsString = JSON.stringify(params);
    const signature = getSignature(paramsString);
    return { sub, public: isPublic, s3: !!env.S3_ACCESS_KEY_ID, params, signature };
  } catch (error) {
    if (error instanceof AppError) throw error;
    throw new AppError(500, 'auth_key_not_found', 'error', {
      ...(error instanceof Error ? { originalError: error } : {}),
    });
  }
}

toSubnet = (ip: string): string | null => {
  if (!ip) return null;
  // Strip IPv4-mapped IPv6 prefix so 192.168.0.1 and ::ffff:192.168.0.1 collapse.
  const normalized = ip.startsWith('::ffff:') ? ip.slice(7) : ip;
  if (isIPv4(normalized)) {
    const parts = normalized.split('.');
    return `${parts[0]}.${parts[1]}.${parts[2]}.0/24`;
  }
  if (isIPv6(normalized)) {
    // Expand to full form, take first 3 groups, zero the rest.
    const groups = expandIPv6(normalized);
    if (!groups) return null;
    return `${groups[0]}:${groups[1]}:${groups[2]}::/48`;
  }
  return null;
}

