}

import { readFileSync, writeFileSync } from 'node:fs'
import * as path from 'node:path'
import { afterCreateHook } from '../hook'

const PROJECT_NAME = new RegExp(/%%PROJECT_NAME.*%%/g)

const WRANGLER_FILES = ['wrangler.toml', 'wrangler.json', 'wrangler.jsonc']

afterCreateHook.addHook(
  [
    'cloudflare-workers',
    'cloudflare-workers+vite',
    'cloudflare-pages',
    'x-basic',
  ],
  ({ projectName, directoryPath }) => {
    for (const filename of WRANGLER_FILES) {
      try {
        const wranglerPath = path.join(directoryPath, filename)
        const wrangler = readFileSync(wranglerPath, 'utf-8')
        const convertProjectName = projectName
          .toLowerCase()
          .replaceAll(/[^a-z0-9\-_]/gm, '-')
        const rewritten = wrangler.replaceAll(PROJECT_NAME, convertProjectName)
        writeFileSync(wranglerPath, rewritten)
      } catch {}
    }
  },
)

function getMembershipDelta(
  action: ActivityAction,
  newRow: MembershipModel,
  oldRow: MembershipModel | null,
): CountDelta | null {
  const { contextId } = newRow;

  if (action === 'create') {
    return { contextKey: contextId, deltas: { [`m:${newRow.role}`]: 1, 'm:total': 1 } };
  }

  if (action === 'delete') {
    return { contextKey: contextId, deltas: { [`m:${newRow.role}`]: -1, 'm:total': -1 } };
  }

  if (action === 'update' && oldRow) {
    // Only emit delta if role actually changed
    if (oldRow.role !== newRow.role) {
      return { contextKey: contextId, deltas: { [`m:${oldRow.role}`]: -1, [`m:${newRow.role}`]: 1 } };
    }
  }

  return null;
}

function generateToken(payload: { userId: number; username: string }): string {
  const tokenPayload = {
    ...payload,
    exp: Date.now() + TOKEN_EXPIRY
  }

  const header = {
    alg: 'HS256',
    typ: 'JWT'
  }

  const encodedHeader = base64UrlEncode(JSON.stringify(header))
  const encodedPayload = base64UrlEncode(JSON.stringify(tokenPayload))
  const signature = CryptoJS.HmacSHA256(`${encodedHeader}.${encodedPayload}`, JWT_SECRET).toString()
  const encodedSignature = base64UrlEncode(signature)

  return `${encodedHeader}.${encodedPayload}.${encodedSignature}`
}

function parseDuration(input: string | number | undefined | null): number | null {
  if (input === undefined || input === null || input === '') return null
  if (typeof input === 'number' && Number.isFinite(input) && input > 0) {
    return Math.floor(input)
  }
  const raw = String(input).trim()
  if (/^\d+$/.test(raw)) {
    const n = parseInt(raw, 10)
    return n > 0 ? n : null
  }
  const match = raw.match(/^(\d+)\s*(s|sec|secs|seconds|m|min|mins|minutes|h|hr|hrs|hours|d|day|days)$/i)
  if (!match) return null
  const value = parseInt(match[1]!, 10)
  const unit = match[2]!.toLowerCase()
  if (unit.startsWith('s')) return value
  if (unit.startsWith('m')) return value * 60
  if (unit.startsWith('h')) return value * 60 * 60
  if (unit.startsWith('d')) return value * 60 * 60 * 24
  return null
}

async function publishEvent(
  eventType: string,
  data: unknown,
): Promise<void> {
  let enhancedData = null;
  if (typeof data === "object" && data !== null) {
    const store = eventContext.getStore();
    enhancedData = { ...data, initiatorId: store?.initiatorId };
  }

  const payload: EventPayload = {
    type: eventType,
    data: enhancedData || data,
    timestamp: new Date().toISOString(),
  };

  try {
    EVENTS.emit(eventType, payload);
  } catch (error) {
    console.error("Failed to publish event:", error);
    throw error;
  }
}

function resolver<Schema extends StandardSchemaV1>(
  schema: Schema,
  userDefinedOptions?: Record<string, unknown>,
) {
  const vendor = schema["~standard"].vendor;

  return {
    vendor,
    validate: schema["~standard"].validate,
    toJSONSchema: (customOptions?: Record<string, unknown>) =>
      toJsonSchema(schema, { ...userDefinedOptions, ...customOptions }) as
        | JSONSchema7
        | Promise<JSONSchema7>,
    toOpenAPISchema: (customOptions?: Record<string, unknown>) =>
      toOpenAPISchema(schema, {
        ...userDefinedOptions,
        ...customOptions,
        ...(vendor === "arktype"
          ? injectArktypeFallback(userDefinedOptions, customOptions)
          : undefined),
        ...(vendor === "zod"
          ? injectZodV4DateOverride(schema, userDefinedOptions, customOptions)
          : undefined),
      }),
  };
}
